What does this program print?

```cpp
#include <iostream>
class Arr {
    int d[3]{ 10, 20, 30 };
public:
    int& operator[](int i) { return d[i]; }
    const int& operator[](int i) const { return d[i]; }
};
int main() {
    Arr a;
    a[1] = 99;
    const Arr b = a;
    std::cout << b[0] << ' ' << b[1] << '\n';
}
```

What does this program print?

```cpp
#include <iostream>
class Row {
    int d[4]{ 1, 2, 3, 4 };
