class Buf {
    int d[5]{ 10, 20, 30, 40, 50 };
public:
    int operator[](int i) const { return d[i]; }  // only overload
};
int main() {
    Buf b;
    b[2] = 50;  // intended write
    std::cout << b[2] << '\n';
}
